import subprocess

def convertDocument(input_file, output_file, output_format):
    # Validate input formats
    if not (input_file.endswith('.docx') or input_file.endswith('.png') or input_file.endswith('.jpg')):
        raise ValueError("Unsupported input format")
    
    # Validate output format
    if output_format not in ['pdf', 'odt']:
        raise ValueError("Unsupported output format")
    
    # Construct the command for LibreOffice headless conversion
    command = [
        '/usr/bin/libreoffice',
        '--headless',
        '--convert-to', output_format,
        '--outdir', '.',
        input_file
    ]
    
    # Execute the command using subprocess
    try:
        subprocess.run(command, check=True)
        print(f"Conversion successful: {output_file}")
    except subprocess.CalledProcessError as e:
        print(f"Conversion failed with error code {e.returncode}")

# Example usage
convertDocument('input.docx', 'output.pdf', 'pdf')